enum IntegrityIssue: String {
    case jailbroken = "Device appears to be jailbroken"
    case debuggerAttached = "Debugger detected"
    case invalidCodeSignature = "Invalid code signature"
    case suspiciousFiles = "Suspicious files detected"
    case simulator = "Running on simulator"
}

struct DeviceIntegrityStatus {
    let issues: [IntegrityIssue]
    
    var isCompromised: Bool {
        return !issues.isEmpty
    }
    
    var isCriticallyCompromised: Bool {
        return issues.contains(.jailbroken) || issues.contains(.debuggerAttached)
    }
    
    var warningMessage: String {
        if issues.isEmpty {
            return ""
        }
        
        var message = "Security Warning:\n"
        for issue in issues {
            message += "• \(issue.rawValue)\n"
        }
        message += "\nYour funds may be at risk. Proceed with caution."
        return message
    }
}

// MARK: - Secure Storage Manager
class SecureStorageManager {
    static let shared = SecureStorageManager()
    
    private let keychainService = "com.cryptowallet.keys"
    private let integrityManager = DeviceIntegrityManager.shared
    
    private init() {}
    
    func storePrivateKey(_ key: Data, identifier: String) -> Bool {
        let integrityStatus = integrityManager.performIntegrityChecks()
        
        if integrityStatus.isCriticallyCompromised {
            logSecurityEvent("Attempted to store private key on compromised device")
            return false
        }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: identifier,
            kSecValueData as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecAttrSynchronizable as String: false
        ]
        
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        
        if status == errSecSuccess {
            logSecurityEvent("Private key stored successfully for \(identifier)")
        } else {
            logSecurityEvent("Failed to store private key: \(status)")
        }
        
        return status == errSecSuccess
    }
    
    func retrievePrivateKey(identifier: String) -> Data? {
        let integrityStatus = integrityManager.performIntegrityChecks()
        
        if integrityStatus.isCriticallyCompromised {
            logSecurityEvent("Attempted to retrieve private key on compromised device")
            return nil
        }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: identifier,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecSuccess {
            logSecurityEvent("Private key retrieved for \(identifier)")
            return result as? Data
        }
        
        return nil
    }
    
    func deletePrivateKey(identifier: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: identifier
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        
        if status == errSecSuccess {
            logSecurityEvent("Private key deleted for \(identifier)")
        }
        
        return status == errSecSuccess
    }
    
    private func logSecurityEvent(_ message: String) {
        let timestamp = ISO8601DateFormatter().string(from: Date())
        print("[\(timestamp)] SECURITY: \(message)")
    }
}

// MARK: - Crypto Wallet Manager
class CryptoWalletManager {
    static let shared = CryptoWalletManager()
    
    private let secureStorage = SecureStorageManager.shared
    private let integrityManager = DeviceIntegrityManager.shared
    
    private init() {}
    
    func generateNewWallet() -> Wallet? {
        let integrityStatus = integrityManager.performIntegrityChecks()
        
        if integrityStatus.isCriticallyCompromised {
            return nil
        }
        
        let privateKey = Curve25519.Signing.PrivateKey()
        let publicKey = privateKey.publicKey
        
        let privateKeyData = privateKey.rawRepresentation
        let publicKeyData = publicKey.rawRepresentation
        
        let address = generateAddress(from: publicKeyData)
        
        let walletId = UUID().uuidString
        
        guard secureStorage.storePrivateKey(privateKeyData, identifier: walletId) else {
            return nil
        }
        
        return Wallet(
            id: walletId,
            address: address,
            publicKey: publicKeyData.base64EncodedString(),
            balance: 0.0
        )
    }
    
    func signTransaction(_ transaction: Transaction, walletId: String) -> SignedTransaction? {
        let integrityStatus = integrityManager.performIntegrityChecks()
        
        if integrityStatus.isCriticallyCompromised {
            return nil
        }
        
        guard let privateKeyData = secureStorage.retrievePrivateKey(identifier: walletId) else {
            return nil
        }
        
        guard let privateKey = try? Curve25519.Signing.PrivateKey(rawRepresentation: privateKeyData) else {
            return nil
        }
        
        let transactionData = transaction.serialize()
        
        guard let signature = try? privateKey.signature(for: transactionData) else {
            return nil
        }
        
        return SignedTransaction(
            transaction: transaction,
            signature: signature.base64EncodedString(),
            timestamp: Date()
        )
    }
    
    func verifyTransaction(_ signedTransaction: SignedTransaction, publicKeyString: String) -> Bool {
        guard let publicKeyData = Data(base64Encoded: publicKeyString),
              let publicKey = try? Curve25519.Signing.PublicKey(rawRepresentation: publicKeyData),
              let signatureData = Data(base64Encoded: signedTransaction.signature) else {
            return false
        }
        
        let transactionData = signedTransaction.transaction.serialize()
        
        return publicKey.isValidSignature(signatureData, for: transactionData)
    }
    
    private func generateAddress(from publicKey: Data) -> String {
        let hash = SHA256.hash(data: publicKey)
        let addressData = Data(hash.prefix(20))
        return "0x" + addressData.map { String(format: "%02x", $0) }.joined()
    }
}

// MARK: - Models
struct Wallet: Codable {
    let id: String
    let address: String
    let publicKey: String
    var balance: Double
}

struct Transaction: Codable {
    let from: String
    let to: String
    let amount: Double
    let nonce: Int
    let gasPrice: Double
    let gasLimit: Int
    
    func serialize() -> Data {
        let string = "\(from)\(to)\(amount)\(nonce)\(gasPrice)\(gasLimit)"
        return string.data(using: .utf8) ?? Data()
    }
}

struct SignedTransaction {
    let transaction: Transaction
    let signature: String
    let timestamp: Date
}

// MARK: - Blockchain Communication Manager
class BlockchainCommunicationManager {
    static let shared = BlockchainCommunicationManager()
    
    private let baseURL = "https://api.blockchain.example.com"
    private let integrityManager = DeviceIntegrityManager.shared
    
    private init() {}
    
    func broadcastTransaction(_ signedTransaction: SignedTransaction, completion: @escaping (Result<String, Error>) -> Void) {
        let integrityStatus = integrityManager.performIntegrityChecks()
        
        if integrityStatus.isCriticallyCompromised {
            completion(.failure(WalletError.deviceCompromised))
            return
        }
        
        guard let url = URL(string: "\(baseURL)/broadcast") else {
            completion(.failure(WalletError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let payload: [String: Any] = [
            "from": signedTransaction.transaction.from,
            "to": signedTransaction.transaction.to,
            "amount": signedTransaction.transaction.amount,
            "nonce": signedTransaction.transaction.nonce,
            "gasPrice": signedTransaction.transaction.gasPrice,
            "gasLimit": signedTransaction.transaction.gasLimit,
            "signature": signedTransaction.signature,
            "timestamp": ISO8601DateFormatter().string(from: signedTransaction.timestamp)
        ]
        
        guard let httpBody = try? JSONSerialization.data(withJSONObject: payload) else {
            completion(.failure(WalletError.serializationError))
            return
        }
        
        request.httpBody = httpBody
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let txHash = json["transactionHash"] as? String else {
                completion(.failure(WalletError.invalidResponse))
                return
            }
            
            completion(.success(txHash))
        }.resume()
    }
    
    func getBalance(address: String, completion: @escaping (Result<Double, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/balance/\(address)") else {
            completion(.failure(WalletError.invalidURL))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let balance = json["balance"] as? Double else {
                completion(.failure(WalletError.invalidResponse))
                return
            }
            
            completion(.success(balance))
        }.resume()
    }
    
    func getTransactionHistory(address: String, completion: @escaping (Result<[TransactionRecord], Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/transactions/\(address)") else {
            completion(.failure(WalletError.invalidURL))
            return
        }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let transactions = try? JSONDecoder().decode([TransactionRecord].self, from: data) else {
                completion(.failure(WalletError.invalidResponse))
                return
            }
            
            completion(.success(transactions))
        }.resume()
    }
}

struct TransactionRecord: Codable {
    let hash: String
    let from: String
    let to: String
    let amount: Double
    let timestamp: Date
    let status: String
}

enum WalletError: Error {
    case deviceCompromised
    case invalidURL
    case serializationError
    case invalidResponse
    case keyGenerationFailed
    case signingFailed
}

// MARK: - Main View Controller
class WalletViewController: UIViewController {
    
    private let walletManager = CryptoWalletManager.shared
    private let blockchainManager = BlockchainCommunicationManager.shared
    private let integrityManager = DeviceIntegrityManager.shared
    
    private var currentWallet: Wallet?
    
    private let addressLabel = UILabel()
    private let balanceLabel = UILabel()
    private let createWalletButton = UIButton(type: .system)
    private let sendButton = UIButton(type: .system)
    private let refreshButton = UIButton(type: .system)
    private let securityStatusLabel = UILabel()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        setupUI()
        performSecurityCheck()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Crypto Wallet"
        
        securityStatusLabel.numberOfLines = 0
        securityStatusLabel.textAlignment = .center
        securityStatusLabel.font = .systemFont(ofSize: 12)
        securityStatusLabel.textColor = .systemRed
        securityStatusLabel.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(securityStatusLabel)
        
        addressLabel.numberOfLines = 0
        addressLabel.textAlignment = .center
        addressLabel.font = .systemFont(ofSize: 14)
        addressLabel.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(addressLabel)
        
        balanceLabel.textAlignment = .center
        balanceLabel.font = .boldSystemFont(ofSize: 32)
        balanceLabel.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(balanceLabel)
        
        createWalletButton.setTitle("Create New Wallet", for: .normal)
        createWalletButton.addTarget(self, action: #selector(createWalletTapped), for: .touchUpInside)
        createWalletButton.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(createWalletButton)
        
        sendButton.setTitle("Send Transaction", for: .normal)
        sendButton.addTarget(self, action: #selector(sendTransactionTapped), for: .touchUpInside)
        sendButton.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(sendButton)
        
        refreshButton.setTitle("Refresh Balance", for: .normal)
        refreshButton.addTarget(self, action: #selector(refreshBalanceTapped), for: .touchUpInside)
        refreshButton.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(refreshButton)
        
        NSLayoutConstraint.activate([
            securityStatusLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            securityStatusLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            securityStatusLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            balanceLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -50),
            balanceLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            addressLabel.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 20),
            addressLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            addressLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            createWalletButton.topAnchor.constraint(equalTo: addressLabel.bottomAnchor, constant: 40),
            createWalletButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            sendButton.topAnchor.constraint(equalTo: createWalletButton.bottomAnchor, constant: 20),
            sendButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            refreshButton.topAnchor.constraint(equalTo: sendButton.bottomAnchor, constant: 20),
            refreshButton.centerXAnchor.constraint(equalTo: view.centerXAnchor)
        ])
        
        updateUI()
    }
    
    private func performSecurityCheck() {
        let integrityStatus = integrityManager.performIntegrityChecks()
        
        if integrityStatus.isCompromised {
            securityStatusLabel.text = integrityStatus.warningMessage
            
            if integrityStatus.isCriticallyCompromised {
                createWalletButton.isEnabled = false
                sendButton.isEnabled = false
                
                let alert = UIAlertController(
                    title: "Security Warning",
                    message: integrityStatus.warningMessage + "\n\nCritical security operations are disabled.",
                    preferredStyle: .alert
                )
                alert.addAction(UIAlertAction(title: "OK", style: .default))
                present(alert, animated: true)
            }
        } else {
            securityStatusLabel.text = "✓ Device integrity verified"
            securityStatusLabel.textColor = .systemGreen
        }
    }
    
    @objc private func createWalletTapped() {
        let integrityStatus = integrityManager.performIntegrityChecks()
        
        if integrityStatus.isCriticallyCompromised {
            showAlert(title: "Error", message: "Cannot create wallet on compromised device")
            return
        }
        
        guard let wallet = walletManager.generateNewWallet() else {
            showAlert(title: "Error", message: "Failed to create wallet")
            return
        }
        
        currentWallet = wallet
        updateUI()
        showAlert(title: "Success", message: "Wallet created successfully!")
    }
    
    @objc private func sendTransactionTapped() {
        let integrityStatus = integrityManager.performIntegrityChecks()
        
        if integrityStatus.isCriticallyCompromised {
            showAlert(title: "Error", message: "Cannot send transactions on compromised device")
            return
        }
        
        guard let wallet = currentWallet else {
            showAlert(title: "Error", message: "No wallet available")
            return
        }
        
        let alert = UIAlertController(title: "Send Transaction", message: "Enter recipient address and amount", preferredStyle: .alert)
        
        alert.addTextField { textField in
            textField.placeholder = "Recipient Address"
        }
        
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let recipientAddress = alert.textFields?[0].text,
                  let amountString = alert.textFields?[1].text,
                  let amount = Double(amountString) else {
                return
            }
            
            self?.sendTransaction(to: recipientAddress, amount: amount, from: wallet)
        })
        
        present(alert, animated: true)
    }
    
    private func sendTransaction(to recipient: String, amount: Double, from wallet: Wallet) {
        let transaction = Transaction(
            from: wallet.address,
            to: recipient,
            amount: amount,
            nonce: Int(Date().timeIntervalSince1970),
            gasPrice: 0.0001,
            gasLimit: 21000
        )
        
        guard let signedTransaction = walletManager.signTransaction(transaction, walletId: wallet.id) else {
            showAlert(title: "Error", message: "Failed to sign transaction")
            return
        }
        
        blockchainManager.broadcastTransaction(signedTransaction) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let txHash):
                    self?.showAlert(title: "Success", message: "Transaction sent!\nHash: \(txHash)")
                case .failure(let error):
                    self?.showAlert(title: "Error", message: "Failed to send transaction: \(error.localizedDescription)")
                }
            }
        }
    }
    
    @objc private func refreshBalanceTapped() {
        guard let wallet = currentWallet else {
            showAlert(title: "Error", message: "No wallet available")
            return
        }
        
        blockchainManager.getBalance(address: wallet.address) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let balance):
                    self?.currentWallet?.balance = balance
                    self?.updateUI()
                case .failure(let error):
                    self?.showAlert(title: "Error", message: "Failed to fetch balance: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func updateUI() {
        if let wallet = currentWallet {
            addressLabel.text = "Address: \(wallet.address)"
            balanceLabel.text = String(format: "%.4f ETH", wallet.balance)
            sendButton.isEnabled = true
            refreshButton.isEnabled = true
        } else {
            addressLabel.text = "No wallet"
            balanceLabel.text = "0.0000 ETH"
            sendButton.isEnabled = false
            refreshButton.isEnabled = false
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

// MARK: - App Delegate
@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        let integrityStatus = DeviceIntegrityManager.shared.performIntegrityChecks()
        
        if integrityStatus.isCompromised {
            print("⚠️ Device integrity issues detected:")
            for issue in integrityStatus.issues {
                print("  - \(issue.rawValue)")
            }
        }
        
        window = UIWindow(frame: UIScreen.main.bounds)
        let viewController = WalletViewController()
        let navigationController = UINavigationController(rootViewController: viewController)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        return true
    }
}